INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (828, 175855, 5, 1294, '流星般的、、、、、、', '一日，在“丝竹乱耳，案牍劳形”之后，偶得片刻宁静之时，吾站于阳台稍息，抬头望眼，欲见天空一片漆黑。我心中微微一颤：这漆黑的天空在街上的钠灯的映衬下，显示出一片死的蜡黄。今天，阳关普照，太阳毫不吝啬的给予地球上每个人一样的温暖。可是，刚过几个小时，整个万里无云的蓝天却变的如此。我不奢求月亮柔光遍布，我不奢求耀眼繁星密布；我只求有那么一点星光，哪怕是稍众即逝的一点点星光；我、、、、、、
<br>    正当我沉思万里之时，突然间，仿佛老天可怜我这祁光人，赐与我一串美丽光尾，一闪而过。“啊，流星！”我不禁的脱口而出。她走了，但已在我心中落下她的全部。她已飞向天的另一边，为那些祁光的人们带去了她的温暖与美好。是的，她走了，悄悄的来，匆匆的去；但她那美丽如音符般，而且飘逸的身影却印在我的脑海里，成为我心中的一盏不灭的明灯，指引着我的灵魂在这茫茫的夜空中飞行。', '一日，在“丝竹乱耳，案牍劳形”之后，偶得片刻宁静之时，吾站于阳台稍息，抬头望眼，欲见天空一片漆黑。我心中微微一颤：这漆黑的天空在街上的钠灯的映衬下，显示出一片死的蜡黄。今天，阳关普照，太阳毫不吝啬的给予地球上每个人一样的温暖。可是，刚过几个小时，整个万里无云的蓝天却变的如此。我不奢求月亮柔光遍布，我不奢求耀眼繁星密布；我只求有那么一点星光，哪怕是稍众即逝的一点点星光；我、、、、、、

正当我沉思万里之时，突然间，仿佛老天可怜我这祁光人，赐与我一串美丽光尾，一闪而过。“啊，流星！”我不禁的脱口而出。她走了，但已在我心中落下她的全部。她已飞向天的另一边，为那些祁光的人们带去了她的温暖与美好。是的，她走了，悄悄的来，匆匆的去；但她那美丽如音符般，而且飘逸的身影却印在我的脑海里，成为我心中的一盏不灭的明灯，指引着我的灵魂在这茫茫的夜空中飞行。', NULL, '2002-08-05 12:37:00', 0, '20020828164942_bbsid_175855_board_5_a365a76b0e.html', '20020828164942');
